INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605450A$$, 2027, $$The AGM-179 Joint Air-to-Ground Missile (JAGM) program is an Army-led, Acquisition Category (ACAT) 1C Major Defense Acquisition Program (MDAP) with joint
interest with the Navy, Marine Corps, and Air Force. JAGM is the next generation, multi-mode, air-to-ground munition replacing legacy HELLFIRE (HF) and HF Longbow
munitions. JAGM will be used for destruction of high-value land and maritime targets, moving or stationary, and is capable of being fired from any platform currently
firing HF from a US Army-issued M299 launcher. JAGM utilizes a HF back-end (propulsion, warhead and control system) with a new-design, Millimeter Wave (MMW)
and Semi-Active Laser (SAL), multi-mode guidance section. The multi-mode capability provides fire-and-forget and precision-point targeting as well as unique, blended
modes of each, for improved capability over legacy munitions.$$, $$The AGM-179 Joint Air-to-Ground Missile (JAGM) program is an Army-led, Acquisition Category (ACAT) IC Major Defense Acquisition Program (MDAP) with joint
interest with the United States (U.S.) Air Force, U.S. Marine Corps (USMC), and U.S. Navy. The JAGM is the next generation of aviation-launched, fire and forget
missiles to replace the HELLFIRE Laser and Longbow radar missiles. JAGM will be used by joint service aircraft for destruction of high value stationary, moving, and
relocatable land and maritime targets from standoff range in day, night, adverse weather, and obscured battlefield conditions.

B. Accomplishments/Planned Programs ($ in Millions)                                                                                          FY 2025            FY 2026       FY 2027
Title: Integration and Counter Measure/Threat Management                                                                                         2.919                 -             -
Description: The Air-to-Ground Missile Systems (AGMS) Product Office and Other Government Agencies (OGAs) will continue
